<?php declare(strict_types=1); namespace App\Models; use App\Enums\AttendanceStatus; use App\Enums\WorkScheduleType; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo;
class EmployeeAttendance extends Model{protected $fillable=['employee_id','attendance_date','checked_in_at','checked_out_at','status','work_schedule_type','latitude','longitude','accuracy','location_text','selfie_path','notes','is_verified','verified_by','verified_at','correction_reason','created_by']; protected function casts():array{return ['attendance_date'=>'date','checked_in_at'=>'datetime','checked_out_at'=>'datetime','verified_at'=>'datetime','status'=>AttendanceStatus::class,'work_schedule_type'=>WorkScheduleType::class,'is_verified'=>'boolean'];} public function scopeFilter($q,array $f){return $q->when($f["date"]??null,fn($q,$v)=>$q->whereDate("attendance_date",$v))->when($f["status"]??null,fn($q,$v)=>$q->where("status",$v))->when($f["employee_id"]??null,fn($q,$v)=>$q->where("employee_id",$v));} public function employee():BelongsTo{return $this->belongsTo(Employee::class);} public function verifier():BelongsTo{return $this->belongsTo(User::class,'verified_by');}}
